                </p>
                ${
                  swapHasExistingManualSwap
                    ? `
                      <label class="choice-option">
                        <input type="radio" name="hf-swap-action" value="cancel" ${this._swapModalAction === "cancel" ? "checked" : ""} />
                        <span>Cancel existing swap</span>
                      </label>
                      <p class="choice-help">
