     </button>`);
} else {
  const futureLabel = isFuture ? "Upcoming" : "Pending";
  if (!canSwap || isDone || isMissed) {
    actionParts.push(`<span class="status-chip ${isDone ? "done" : isMissed ? "missed" : "pending"}">
         ${isDone ? "Done" : isMissed ? "Missed" : futureLabel}
       </span>`);
  }
}

if (canSwap) {
