       ${isDoneSaving || isSwapSaving ? "disabled" : ""}
     >
       <ha-icon icon="mdi:swap-horizontal"></ha-icon>
       <span>${isSwapSaving ? "Saving..." : swapLabel}</span>
     </button>`);
}

const actionControl = actionParts.join("");

return `
