        );
        const sourceLabel = sourceElapsed ? ` (${sourceElapsed})` : "";
        ctxParts.push(
          `Swap return week. Originally ${this._escape(historyOriginalName || "another flatmate")}'s turn, swapped with ${this._escape(historyAssigneeName)}${sourceLabel}.`
