            </div>
            <span class="compact-week"><span class="compact-date">${compactDateLabel}</span>${compactContextHtml}</span>
            ${compactNote ? `<span class="compact-note">${this._escape(compactNote)}</span>` : ""}
          </li>
        `;
      })
      .join("");

    this._root.innerHTML = `
