              : `
                <div class="header">
                  <div>
                    <h2>${this._escape(this._config.title)}</h2>
                    <p>${this._escape(currentAssigneeName)} • ${statusLabel}</p>
                  </div>
                  <span class="header-status ${currentStatus}">${statusLabel}</span>
                </div>
