                  </ul>
                `
                : `
                  <ul class="week-list">
                    ${weekRows || '<li class="empty-list">No schedule data yet</li>'}
                  </ul>
                `
            }
          </section>

          ${!compactMode && errorMessage ? `<div class="error">${errorMessage}</div>` : ""}
        </div>

        ${!compactMode && this._modalOpen && modalWeek ? `
          <div class="modal-backdrop done-modal-backdrop">
