          color: var(--success-color, #4caf50);
          background: color-mix(in srgb, var(--success-color, #4caf50) 14%, var(--card-background-color));
          border-color: color-mix(in srgb, var(--success-color, #4caf50) 40%, var(--divider-color));
        }

        .header-status.missed {
          color: var(--warning-color, #f57c00);
          background: color-mix(in srgb, var(--warning-color, #f57c00) 14%, var(--card-background-color));
          border-color: color-mix(in srgb, var(--warning-color, #f57c00) 40%, var(--divider-color));
        }

        .header-status.pending {
          color: var(--primary-text-color);
        }

        section h3 {
          margin: 0 0 8px;
          font-size: 0.92rem;
          color: var(--secondary-text-color);
          text-transform: uppercase;
          letter-spacing: 0.04em;
        }

        .week-list {
          list-style: none;
          margin: 0;
          padding: 0;
          display: grid;
          gap: 8px;
        }

        .week-row {
          display: grid;
          grid-template-columns: 1fr auto;
          gap: 10px;
          align-items: center;
          border: 1px solid var(--divider-color);
          border-radius: 12px;
          padding: 10px;
        }

        .compact-week-list {
          list-style: none;
          margin: 0;
          padding: 0;
          border: 1px solid var(--divider-color);
          border-radius: 12px;
          overflow: hidden;
          background: var(--card-background-color);
          display: grid;
        }

        .compact-week-row {
          display: grid;
          gap: 4px;
          align-items: start;
          padding: 8px 10px;
          border-bottom: 1px solid var(--divider-color);
          font-size: 0.83rem;
          line-height: 1.25;
