 69→  _buildStateSnapshot(hass) {
 70→    if (!hass || !this._config?.entity) {
 71→      return "";
 72→    }
 73→    const stateObj = hass.states[this._config.entity];
 74→    if (!stateObj) {
 75→      return "missing";
 76→    }
 77→    const attrs = stateObj.attributes || {};
 78→    return JSON.stringify({
 79→      state: stateObj.state,
 80→      open_items: attrs.open_items || [],
 81→      suggestions: attrs.suggestions || [],
 82→      service_domain: attrs.service_domain || "",
 83→      service_add_item: attrs.service_add_item || "",
 84→      service_complete_item: attrs.service_complete_item || "",
 85→      service_delete_item: attrs.service_delete_item || "",
 86→    });
 87→  }
