 89→  _escape(value) {
 90→    return String(value ?? "")
 91→      .replaceAll("&", "&amp;")
 92→      .replaceAll("<", "&lt;")
 93→      .replaceAll(">", "&gt;")
 94→      .replaceAll('"', "&quot;")
 95→      .replaceAll("'", "&#039;");
 96→  }
