120→    const token = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
121→    this._optimisticRecents = [
122→      { token, key: normalized.key, name: normalized.name },
123→      ...this._optimisticRecents.filter((entry) => entry.key !== normalized.key),
124→    ].slice(0, 120);
