132→    this._optimisticRecents = this._optimisticRecents.filter((entry) => entry.token !== token);
133→  }
134→
135→  _dropOptimisticRecentByName(name) {
136→    const normalized = this._normalizeName(name);
137→    if (!normalized.key) {
138→      return;
139→    }
140→    this._optimisticRecents = this._optimisticRecents.filter((entry) => entry.key !== normalized.key);
141→  }
142→
143→  _toTimestamp(value) {
144→    const parsed = Date.parse(String(value || ""));
145→    return Number.isNaN(parsed) ? 0 : parsed;
146→  }
147→
148→  _sortOpenItems(items) {
149→    return [...items].sort((a, b) => {
150→      const aPending = a?.pending_add ? 1 : 0;
151→      const bPending = b?.pending_add ? 1 : 0;
152→      if (aPending !== bPending) {
153→        return bPending - aPending;
154→      }
155→
156→      const byDate = this._toTimestamp(b?.added_at) - this._toTimestamp(a?.added_at);
157→      if (byDate !== 0) {
158→        return byDate;
159→      }
160→
161→      return String(a?.name || "").localeCompare(String(b?.name || ""), undefined, {
162→        sensitivity: "base",
163→      });
164→    });
165→  }
166→
167→  _relativeAdded(isoString) {
168→    if (!isoString) {
169→      return "added recently";
170→    }
171→    const date = new Date(isoString);
172→    if (Number.isNaN(date.getTime())) {
173→      return "added recently";
174→    }
175→
176→    const diffSeconds = Math.round((Date.now() - date.getTime()) / 1000);
177→    const abs = Math.abs(diffSeconds);
178→    const rtf = new Intl.RelativeTimeFormat(undefined, { numeric: "auto" });
179→
180→    const units = [
181→      [60, "second"],
182→      [60, "minute"],
183→      [24, "hour"],
184→      [7, "day"],
185→      [4.34524, "week"],
186→      [12, "month"],
187→      [Number.POSITIVE_INFINITY, "year"],
188→    ];
189→
190→    let value = diffSeconds;
191→    let unit = "second";
192→    let current = abs;
193→
194→    for (const [base, nextUnit] of units) {
195→      unit = nextUnit;
196→      if (current < base) {
197→        break;
198→      }
199→      value = Math.round(value / base);
200→      current = current / base;
201→    }
202→
203→    return `added ${rtf.format(-Math.abs(value), unit)}`;
204→  }
205→
206→  async _callService(service, data) {
207→    if (!this._hass || !this._stateObj) {
208→      return;
209→    }
210→    const meta = this._serviceMeta(this._stateObj.attributes || {});
211→    await this._hass.callService(meta.domain, service, data);
212→    this._errorMessage = "";
213→  }
214→
215→  async _addItem(name) {
216→    const normalized = String(name || "").trim();
217→    if (!normalized) {
218→      return;
219→    }
220→
221→    const key = normalized.toLowerCase();
222→    this._dropOptimisticRecentByName(normalized);
223→    if (this._pendingAdds.some((row) => row.key === key)) {
224→      return;
225→    }
226→    const openItems = Array.isArray(this._stateObj?.attributes?.open_items)
227→      ? this._stateObj.attributes.open_items
228→      : [];
229→    const currentOpenCount = openItems.filter(
230→      (item) => String(item?.name || "").trim().toLowerCase() === key
231→    ).length;
232→    const currentPendingCount = this._pendingAdds.filter((row) => row.key === key).length;
233→    const tempId = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
234→
235→    this._pendingAdds.push({
236→      tempId,
237→      key,
238→      name: normalized,
239→      addedAt: new Date().toISOString(),
240→      expectedOpenCount: currentOpenCount + currentPendingCount + 1,
241→    });
242→
243→    this._draftName = "";
244→    this._errorMessage = "";
245→    this._render();
246→
247→    try {
248→      const meta = this._serviceMeta(this._stateObj.attributes || {});
249→      await this._callService(meta.addItem, { name: normalized });
250→    } catch (error) {
251→      this._pendingAdds = this._pendingAdds.filter((row) => row.tempId !== tempId);
252→      this._draftName = normalized;
253→      this._errorMessage = error?.message || "Unable to add shopping item";
254→      this._render();
255→    }
256→  }
257→
258→  async _completeItem(id, name = "") {
259→    if (!id || this._pendingItemIds.has(id)) {
260→      return;
261→    }
262→    const optimisticRecentToken = this._pushOptimisticRecent(name);
263→    this._errorMessage = "";
264→    this._pendingItemIds.add(id);
265→    this._render();
266→    try {
267→      const meta = this._serviceMeta(this._stateObj.attributes || {});
268→      await this._callService(meta.completeItem, { item_id: id });
269→    } catch (error) {
270→      this._dropOptimisticRecentByToken(optimisticRecentToken);
271→      this._pendingItemIds.delete(id);
272→      this._errorMessage = error?.message || "Unable to mark item as bought";
273→      this._render();
274→    }
275→  }
276→
277→  async _deleteItem(id, name) {
278→    if (!id || this._pendingItemIds.has(id)) {
279→      return;
280→    }
281→    const confirmed = window.confirm(`Remove "${name}" from the shopping list?`);
282→    if (!confirmed) {
283→      return;
284→    }
