286→    const optimisticRecentToken = this._pushOptimisticRecent(name);
287→    this._errorMessage = "";
288→    this._pendingItemIds.add(id);
289→    this._render();
290→    try {
291→      const meta = this._serviceMeta(this._stateObj.attributes || {});
292→      await this._callService(meta.deleteItem, { item_id: id });
293→    } catch (error) {
294→      this._dropOptimisticRecentByToken(optimisticRecentToken);
295→      this._pendingItemIds.delete(id);
296→      this._errorMessage = error?.message || "Unable to remove item";
297→      this._render();
298→    }
299→  }
