301→  _bindEvents() {
302→    const form = this._root.querySelector("#hf-add-form");
303→    const input = this._root.querySelector("#hf-item-input");
304→    const stopBubble = (event) => event.stopPropagation();
305→
306→    input?.addEventListener("input", (event) => {
