391→    const pendingOpenItems = this._pendingAdds.map((row) => ({
392→      id: `pending-${row.tempId}`,
393→      name: row.name,
394→      added_at: row.addedAt,
395→      added_by_name: null,
396→      pending_add: true,
397→    }));
398→
399→    const openIdSet = new Set(
400→      openItems
401→        .map((item) => Number(item?.id))
